// Format CRM companies for Lusha Company Bulk Enrichment
const items = $input.all();
let idCounter = 1;

const companies = items
  .filter(item => item.json.properties?.domain)
  .map(item => ({
    id: String(idCounter++),
    domain: item.json.properties.domain,
    crmId: item.json.id,
    crmName: item.json.properties?.name || '',
    crmEmployees: item.json.properties?.numberofemployees || '0',
    crmRevenue: item.json.properties?.annualrevenue || '0'
  }));

const payload = { companies: companies.map(c => ({ id: c.id, domain: c.domain })) };

// Store CRM data alongside payload for signal detection later
return [{
  json: {
    companiesPayload: JSON.stringify(payload),
    crmLookup: Object.fromEntries(
      companies.map(c => [c.domain, { crmId: c.crmId, name: c.crmName, employees: c.crmEmployees, revenue: c.crmRevenue }])
    )
  }
}];

// Detect signals for each company in the bulk response
// Match bulk results back to CRM data using domain
const bulkResults = $input.all();
const crmLookup = $('Format Companies for Bulk').first().json.crmLookup;

const output = [];
for (const item of bulkResults) {
  const lusha = item.json;
  const domain = lusha.domain || '';
  const crm = crmLookup[domain] || {};

  const signals = [];
  const crmEmpCount = parseInt(crm.employees || '0');
  const lushaEmployees = parseInt(lusha.employees || '0');

  // Growth signal: headcount increased 10%+
  if (crmEmpCount > 0 && lushaEmployees > 0) {
    const growth = ((lushaEmployees - crmEmpCount) / crmEmpCount) * 100;
    if (growth >= 10) {
      signals.push({
        type: 'headcount_growth',
        detail: `+${growth.toFixed(0)}% (${crmEmpCount} → ${lushaEmployees})`,
        strength: growth >= 25 ? 'strong' : 'moderate'
      });
    }
  }

  // Revenue growth check
  const lushaRevMax = Array.isArray(lusha.revenueRange) ? lusha.revenueRange[1] : 0;
  const crmRevenue = parseFloat(crm.revenue || '0');
  if (lushaRevMax > 0 && crmRevenue > 0) {
    const revGrowth = ((lushaRevMax - crmRevenue) / crmRevenue) * 100;
    if (revGrowth >= 15) {
      signals.push({ type: 'revenue_growth', detail: `+${revGrowth.toFixed(0)}%`, strength: 'strong' });
    }
  }

  // Funding signal
  if (lusha.funding && Object.keys(lusha.funding).length > 0) {
    signals.push({ type: 'has_funding_data', detail: 'Funding data available', strength: 'moderate' });
  }

  output.push({
    json: {
      companyId: crm.crmId || '',
      companyName: lusha.name || crm.name || '',
      domain,
      currentEmployeeCount: lushaEmployees,
      previousEmployeeCount: crmEmpCount,
      industry: lusha.mainIndustry,
      revenueRange: lusha.revenueRange,
      signals,
      hasSignals: signals.length > 0,
      signalStrength: signals.some(s => s.strength === 'strong') ? 'strong' : signals.length > 0 ? 'moderate' : 'none'
    }
  });
}

return output;
